// 1. Grab the clean data for THIS SPECIFIC ITEM (Since it runs once per item)
const data = $input.item.json;

// 2. DYNAMIC SUPPLIER LOGIC
const isVillaGuelfa = (data.supplier_name || '').toUpperCase().includes('GUELFA');
const fornitoreName = isVillaGuelfa ? 'VILLA GUELFA S.R.L.' : 'DRINK INTERNATIONAL SPA';
const fornitorePiva = isVillaGuelfa ? '02537910040' : 'IT00926410010';

// 3. CREATE A UNIQUE FILE NAME (Adds a timestamp to prevent overwriting!)
let rawCustomer = data.customer_name || 'Ordine_Fornitore';
let cleanCustomer = rawCustomer.replace(/[^a-zA-Z0-9]/g, '_').toUpperCase();
let orderSuffix = data.order_number 
    ? String(data.order_number).replace(/[^a-zA-Z0-9]/g, '') 
    : new Date().getTime() + "_" + Math.floor(Math.random() * 1000);

let safeFilename = `${cleanCustomer}_${orderSuffix}.pdf`;

// 4. PRE-CALCULATE TOTALS & BUILD TABLE ROWS
let totalQty = 0;
let totalImporto = 0;
let itemsHtml = '';

const itemsList = data.items || [];

if (itemsList.length === 0) {
    itemsHtml = `<tr><td colspan="9" style="text-align:center; padding:20px; background-color:#FFF2CC; color:red;">Nessun articolo trovato.</td></tr>`;
} else {
    itemsList.forEach((lineItem, index) => {
        let safeQty = parseFloat(lineItem.qty) || 0;
        let safePrice = parseFloat(String(lineItem.unit_price || lineItem.price || 0).replace(',', '.')) || 0;
        let calculatedNet = safeQty * safePrice;
        let discountText = '';

        // --- NEW BULLETPROOF DISCOUNT FORMATTER & MATH LOGIC ---
        if (lineItem.discount !== null && lineItem.discount !== undefined && lineItem.discount !== "") {
            let rawDiscount = lineItem.discount;
            let discountArrayForMath = [];

            // 1. Normalize whatever input we got into a clean array
            if (Array.isArray(rawDiscount)) {
                discountArrayForMath = rawDiscount.map(String);
            } else if (typeof rawDiscount === 'string' && rawDiscount.includes('+')) {
                discountArrayForMath = rawDiscount.split('+').map(p => p.trim());
            } else if (typeof rawDiscount === 'number') {
                if (rawDiscount > 0 && rawDiscount < 1) {
                    discountArrayForMath = [(rawDiscount * 100).toFixed(0) + "%"];
                } else {
                    discountArrayForMath = [rawDiscount.toString()];
                }
            } else {
                discountArrayForMath = [String(rawDiscount).trim()];
            }

            // 2. Format the text AND calculate the net price simultaneously
            let formattedParts = [];
            for (let part of discountArrayForMath) {
                // Formatting for the HTML table
                let cleanPart = part.replace(/\s/g, '').replace(/,/g, '.');
                if (cleanPart !== "") {
                    let formattedPart = cleanPart.includes('%') ? cleanPart : cleanPart + '%';
                    formattedParts.push(formattedPart);

                    // Math for the net price
                    let pct = parseFloat(cleanPart.replace('%', ''));
                    if (!isNaN(pct) && pct > 0) {
                        calculatedNet = calculatedNet * (1 - (pct / 100));
                    }
                }
            }
            discountText = formattedParts.join(" + ");
        }
        // --- END DISCOUNT LOGIC ---

        totalQty += safeQty;
        totalImporto += calculatedNet;

        itemsHtml += `
        <tr>
            <td class="bg-light-blue center" style="font-weight:bold; color:#203764;">${index + 1}</td>
            <td class="bg-light-blue center">${lineItem.supplier_code || ''}</td>
            <td class="bg-light-blue center">${lineItem.item_code || lineItem.code || ''}</td>
            <td class="bg-yellow left">${lineItem.desc || ''}</td>
            <td class="bg-yellow center">${lineItem.um || 'PZ'}</td>
            <td class="bg-yellow center">${safeQty}</td>
            <td class="bg-yellow right">€ ${safePrice.toFixed(2)}</td>
            <td class="bg-yellow center">${discountText}</td>
            <td class="bg-light-blue right">€ ${calculatedNet.toFixed(2)}</td>
        </tr>
        `;
    });
}

// 4.5. BUILD THE NOTES BOX (Only shows if note_ordine exists!)
let noteHtml = '';
if (data.note_ordine && data.note_ordine.trim() !== '' && data.note_ordine !== 'null') {
    noteHtml = `
    <div style="margin-top: 30px; border: 2px solid #D83B01; background-color: #FFF4CE; padding: 10px;">
        <div style="font-weight: bold; color: #D83B01; font-size: 11pt; margin-bottom: 5px;">🚨 NOTE / COMUNICAZIONI EMAIL:</div>
        <div style="font-size: 9.5pt; color: #000; white-space: pre-wrap;">${data.note_ordine}</div>
    </div>
    `;
}

// 5. BUILD THE TEMPLATE
const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    @page { size: A4 landscape; margin: 10mm; background-color: #ffffff; }
    body { font-family: Arial, sans-serif; font-size: 8.5pt; margin: 0; padding: 0; color: #000; }
    .bg-dark-blue { background-color: #203764; color: white; }
    .bg-mid-blue { background-color: #305496; color: white; }
    .bg-yellow { background-color: #FFF2CC; border: 1px solid #E6C800 !important; }
    .bg-light-blue { background-color: #DDEEFF; border: 1px solid #9DC3E6 !important; color: #203764; }
    .bg-white { background-color: #FFFFFF; border: 1px solid #B7B7B7 !important; }
    .header-banner { text-align: center; padding: 6px; font-size: 14pt; font-weight: bold; }
    .sub-banner { text-align: center; padding: 4px; font-size: 9pt; margin-bottom: 15px; }
    table { width: 100%; border-collapse: collapse; table-layout: fixed; margin-bottom: 10px; }
    td { padding: 4px; vertical-align: middle; border: 1px solid #ffffff; }
    .label-cell { text-align: right; font-weight: bold; color: #203764; width: 15%; padding-right: 8px; }
    .input-cell { width: 35%; height: 20px; font-weight: bold; padding-left: 5px; }
    .items-table { width: 100%; border-collapse: collapse; margin-top: 5px; }
    .items-table th { background-color: #203764; color: white; font-weight: bold; padding: 6px; text-align: center; border: 1px solid #ffffff;}
    .items-table td { border: 1px solid #D0D8E8; padding: 5px; }
    .center { text-align: center; }
    .left { text-align: left; }
    .right { text-align: right; }
  </style>
</head>
<body>
    <div class="bg-dark-blue header-banner">${fornitoreName} — ORDINE FORNITORE</div>
    <div class="bg-mid-blue sub-banner">Generato Automaticamente (Estrazione AI)</div>
    <table>
        <tr>
            <td class="label-cell">N. DOCUMENTO:</td>
            <td class="input-cell bg-yellow">${data.order_number || ''}</td>
            <td class="label-cell">NOME CLIENTE:</td>
            <td class="input-cell bg-yellow" style="color: #000;">${data.customer_name || ''}</td>
        </tr>
        <tr>
            <td class="label-cell">DATA EMISSIONE:</td>
            <td class="input-cell bg-yellow">${data.issue_date || ''}</td>
            <td class="label-cell">P.IVA:</td>
            <td class="input-cell bg-light-blue">${data.piva_cliente || ''}</td>
        </tr>
        <tr>
            <td class="label-cell">DATA CONSEGNA:</td>
            <td class="input-cell bg-yellow">${data.delivery_date || ''}</td>
            <td class="label-cell">CODE:</td>
            <td class="input-cell bg-light-blue"></td>
        </tr>
        <tr>
            <td class="label-cell">DESTINAZIONE:</td>
            <td class="input-cell bg-yellow">${data.destination || ''}</td>
            <td class="label-cell">INDIRIZZO:</td>
            <td class="input-cell bg-light-blue"></td>
        </tr>
        <tr>
            <td class="label-cell">NOTE ORDINE:</td>
            <td class="input-cell bg-yellow">${data.special_instructions || ''}</td>
            <td class="label-cell">TELEFONO:</td>
            <td class="input-cell bg-light-blue">${data.phone || ''}</td>
        </tr>
        <tr>
            <td class="label-cell"></td>
            <td class="input-cell"></td>
            <td class="label-cell">EMAIL:</td>
            <td class="input-cell bg-light-blue">${data.email || ''}</td>
        </tr>
        <tr>
            <td class="label-cell"></td>
            <td class="input-cell"></td>
            <td class="label-cell">FAX:</td>
            <td class="input-cell bg-light-blue">${data.fax || ''}</td>
        </tr>
    </table>
    <table>
        <tr>
            <td class="label-cell">COND. PAGAMENTO:</td>
            <td class="input-cell bg-light-blue">${data.payment_terms || ''}</td>
            <td class="label-cell">LISTINO / SCONTO:</td>
            <td class="input-cell bg-light-blue">${data.discount || ''}</td>
        </tr>
        <tr>
            <td class="label-cell"></td>
            <td class="input-cell"></td>
            <td class="label-cell">FORNITORE:</td>
            <td class="input-cell bg-white" style="color: #000;">${fornitoreName}</td>
        </tr>
        <tr>
            <td class="label-cell"></td>
            <td class="input-cell"></td>
            <td class="label-cell">P.IVA FORN.:</td>
            <td class="input-cell bg-white" style="color: #000;">${fornitorePiva}</td>
        </tr>
    </table>
    <table>
        <tr>
            <td class="label-cell">TOTALE QUANTITÀ:</td>
            <td class="input-cell bg-light-blue center">${totalQty}</td>
            <td class="label-cell">TOTALE IMPORTO:</td>
            <td class="input-cell bg-light-blue center">€ ${totalImporto.toFixed(2)}</td>
        </tr>
    </table>
    <table class="items-table">
        <thead>
            <tr>
                <th style="width: 3%;">#</th>
                <th style="width: 14%;">CODICE FORNITORE</th>
                <th style="width: 14%;">CODICE ARTICOLO</th>
                <th style="width: 32%;">DESCRIZIONE</th>
                <th style="width: 4%;">U.M.</th>
                <th style="width: 6%;">QTÀ</th>
                <th style="width: 10%;">PREZZO LORDO €</th>
                <th style="width: 7%;">SCONTO %</th>
                <th style="width: 10%;">IMPORTO NETTO €</th>
            </tr>
        </thead>
        <tbody>
            ${itemsHtml}
        </tbody>
    </table>

    ${noteHtml}

</body>
</html>`;

// 6. OUTPUT THIS SINGLE ITEM TO RAILWAY
const binaryData = Buffer.from(html, 'utf8').toString('base64');

return {
  json: { 
    orderData: data,
    pdfFileName: safeFilename
  },
  binary: {
    "index.html": {
      data: binaryData,
      mimeType: "text/html",
      fileName: "index.html"
    }
  }
};

// Check if the 'data' PDF was created for this specific item
if ($input.item.binary && $input.item.binary.data) {

  // Rename the file using the JSON field for this item
  $input.item.binary.data.fileName = $input.item.json.pdfFileName;

}

// Return the updated item back to the workflow
return $input.item;

const results = [];

for (const item of $input.all()) {
  const raw =
    item.json?.candidates?.[0]?.content?.parts?.[0]?.text ??
    item.json?.content?.parts?.[0]?.text ??
    "";

  const clean = raw
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  if (!clean || clean === '{}' || clean === '[]') {
    continue;
  }

  if (!clean.endsWith('}')) {
    results.push({ json: {
      error: true,
      reason: "truncated",
      raw: clean,
      message: "Gemini troncato - aumenta maxOutputTokens"
    }});
    continue;
  }

  try {
    const parsed = JSON.parse(clean);
    const orders = parsed.orders ?? [parsed];
    for (const order of orders) {
      if (
        !order.customer_name &&
        !order.order_number &&
        (!order.items || order.items.length === 0)
      ) {
        continue;
      }
      results.push({ json: order });
    }
  } catch(e) {
    results.push({ json: {
      error: true,
      reason: "parse_failed",
      raw: clean,
      message: e.message
    }});
  }
}

if (results.length === 0) {
  return [{ json: {
    error: true,
    reason: "no_valid_orders",
    message: "Nessun ordine valido trovato"
  }}];
}

return results;

const allItems = $input.all();
const rows = allItems.map(item => {
  const r = item.json.row || item.json;
  return Array.isArray(r) ? r : Object.values(r);
});

const emailSubject = $('New Email with Attachment').first().json.subject ?? '';
const emailBody = $('New Email with Attachment').first().json.textPlain 
  || $('New Email with Attachment').first().json.text 
  || '';

function clean(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function cleanCode(v) {
  return String(v).trim().replace(/\.0+$/, '');
}

function fixDate(v) {
  if (!v) return '';
  if (typeof v === 'number' && v > 40000) {
    const d = new Date(Math.round((v - 25569) * 86400 * 1000));
    return `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
  }
  const s = String(v).trim();
  const m = s.match(/^(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{2})$/);
  if (m) return `${m[1].padStart(2,'0')}/${m[2].padStart(2,'0')}/20${m[3]}`;
  return s;
}

function isProductCode(v) {
  const s = String(v).trim().replace(/\.0+$/, '');
  return /^2[0-9]{3,4}$/.test(s);
}

function isPositiveQty(v) {
  if (v === null || v === undefined || v === '') return false;
  if (isProductCode(v)) return false;
  const n = parseFloat(String(v));
  return !isNaN(n) && n > 0;
}

const allText = rows.map(r => r.join(' ')).join('\n');

// Detect multi-destination list
const hasAddressStructure = rows.some(r => {
  const line = r.map(v => clean(v)).join(' ');
  return /NOMINATIVO|INDIRIZZO|LOCALITA/i.test(line);
});
const hasNoProductCodes = !rows.some(r => isProductCode(r[0]));
const isMultiDestination = hasAddressStructure && hasNoProductCodes;

if (isMultiDestination) {
  return [{
    json: {
      text: allText,
      emailSubject,
      emailBody,
      useHttpRequest: true,
      orders: [{
        customer_name: '',
        supplier_name: 'VILLA GUELFA S.R.L.',
        order_number: '',
        issue_date: '',
        delivery_date: '',
        destination: '',
        note_ordine: '',
        phone: '',
        email: '',
        fax: '',
        piva_cliente: '',
        cond_pagamento: '',
        listino_sconto: '',
        items: []
      }]
    }
  }];
}

// Detect catalog type
const firstDataRow = rows.find(r => isProductCode(r[0]));
const isThreeColCatalog = firstDataRow && firstDataRow.length >= 8 && 
  (isProductCode(firstDataRow[4]) || isProductCode(firstDataRow[8]));

const hasQtyLastCol = rows.some(r => {
  const last = r[r.length - 1];
  return isProductCode(r[0]) && isPositiveQty(last) && r.length > 5;
});

// Extract metadata
let customer_name = '';
let order_number = '';
let issue_date = '';
let delivery_date = '';
let destination = '';
let phone = '';
let email_addr = '';
let piva = '';
let cond_pagamento = '';
let listino_sconto = '';
const notes = [];

for (const row of rows) {
  const line = row.map(v => clean(v)).join(' ').trim();
  if (!line) continue;
  if (/RAGIONE SOCIALE/i.test(line)) {
    const m = line.match(/RAGIONE SOCIALE[:\s_]*([A-Z][A-Z\s&\.]+?)(?:\s{3,}|$)/i);
    if (m) customer_name = m[1].trim();
  }
  if (/^AGENZIA|^F\.LLI|^DITTA/i.test(line) && !customer_name) {
    customer_name = clean(row[0] || row[1] || '');
  }
  if (/NUMERO ORDINE|ordine\s+\d/i.test(line)) {
    const m = line.match(/(?:NUMERO ORDINE|ordine)\s*[_'\s]*(\d+)/i);
    if (m) order_number = m[1];
  }
  if (/DATA ORDINE/i.test(line)) {
    const m = line.match(/(\d{1,2}[\.\/-]\d{1,2}[\.\/-]\d{2,4})/);
    if (m) issue_date = fixDate(m[1]);
  }
  if (/CONSEGNA/i.test(line) && !delivery_date) {
    const m = line.match(/(\d{1,2}[\/\.-]\d{1,2}[\/\.-]\d{2,4})/);
    if (m) delivery_date = fixDate(m[1]);
  }
  if (/LUOGO CONSEGNA/i.test(line)) {
    const m = line.replace(/LUOGO CONSEGNA MERCE/i, '').replace(/_+/g, '').trim();
    if (m.length > 3) destination = m;
  }
  if (/MAIL|email/i.test(line)) {
    const m = line.match(/[\w\.-]+@[\w\.-]+\.\w+/);
    if (m && !m[0].includes('villaguelfa')) email_addr = m[0];
  }
  if (/TEL|CELL/i.test(line)) {
    const m = line.match(/[\d\s\+\-]{8,}/);
    if (m) phone = m[0].trim();
  }
  if (/P\.?\s*IVA/i.test(line)) {
    const m = line.match(/\b(\d{11})\b/);
    if (m && m[1] !== '02537910040') piva = m[1];
  }
  if (/PAGAMENTO|MODALITA/i.test(line)) {
    const cleaned = line.replace(/MODALITA['\s]*DI PAGAMENTO[:\s]*/i, '')
      .replace(/_+/g, '').trim();
    if (cleaned.length > 2) cond_pagamento = cleaned;
  }
  if (/SCONTO/i.test(line) && !/DESCRIZIONE/i.test(line)) {
    const m = line.match(/SCONTO[\s:]*([\d%\+\s,\.]+)/i);
    if (m) listino_sconto = m[1].trim();
  }
  if (/URGENTE|PRE FATTURA|ANNULLA|RITIRARE|ASSEGNO|COLLI NR/i.test(line)) {
    notes.push(line);
  }
}

if (!customer_name) {
  for (const row of rows.slice(0, 5)) {
    const v = clean(row[0] || row[1] || '');
    if (v && v.length > 3 && 
        !/(SPETT|VILLA GUELFA|ORDINE|DATA)/i.test(v) &&
        /[A-Z]{3,}/.test(v)) {
      customer_name = v;
      break;
    }
  }
}

// Parse items
const items = [];

if (isThreeColCatalog) {
  for (const row of rows) {
    if (isProductCode(row[0]) && isPositiveQty(row[2])) {
      items.push({
        supplier_code: cleanCode(row[0]),
        item_code: '',
        desc: clean(row[1]),
        um: 'PZ',
        qty: parseFloat(row[2]),
        price: 0,
        discount: listino_sconto ? [listino_sconto] : [],
        net: ''
      });
    }
    if (row.length > 6 && isProductCode(row[4]) && isPositiveQty(row[6])) {
      items.push({
        supplier_code: cleanCode(row[4]),
        item_code: '',
        desc: clean(row[5]),
        um: 'PZ',
        qty: parseFloat(row[6]),
        price: 0,
        discount: listino_sconto ? [listino_sconto] : [],
        net: ''
      });
    }
    if (row.length > 11 && isProductCode(row[8]) && isPositiveQty(row[11])) {
      items.push({
        supplier_code: cleanCode(row[8]),
        item_code: '',
        desc: clean(row[9]),
        um: 'PZ',
        qty: parseFloat(row[11]),
        price: 0,
        discount: listino_sconto ? [listino_sconto] : [],
        net: ''
      });
    }
  }
} else if (hasQtyLastCol) {
  for (const row of rows) {
    if (!isProductCode(row[0])) continue;
    const qty = parseFloat(row[row.length - 1]);
    if (!isNaN(qty) && qty > 0) {
      let price = 0;
      for (let i = row.length - 2; i >= 2; i--) {
        const v = clean(row[i]).replace('€', '').replace(',', '.').trim();
        const n = parseFloat(v);
        if (!isNaN(n) && n > 1 && n < 1000) { price = n; break; }
      }
      items.push({
        supplier_code: cleanCode(row[0]),
        item_code: '',
        desc: clean(row[1]),
        um: 'PZ',
        qty: qty,
        price: price,
        discount: [],
        net: ''
      });
    }
  }
} else {
  for (const row of rows) {
    if (!isProductCode(row[0])) continue;
    let qty = 0;
    let price = 0;
    if (row.length >= 5 && isPositiveQty(row[4])) {
      qty = parseFloat(row[4]);
      price = parseFloat(String(row[3] || 0).replace(',', '.')) || 0;
    } else if (row.length >= 3 && isPositiveQty(row[2])) {
      qty = parseFloat(row[2]);
    }
    if (qty > 0) {
      let discountArr = [];
      if (listino_sconto) {
        const parts = listino_sconto.split(/\+/);
        discountArr = parts.map(p => {
          const n = parseFloat(p.replace('%','').trim());
          return isNaN(n) ? p.trim() : n + '%';
        }).filter(p => p);
      }
      items.push({
        supplier_code: cleanCode(row[0]),
        item_code: '',
        desc: clean(row[1]),
        um: clean(row[2]) && !isPositiveQty(row[2]) ? clean(row[2]) : 'PZ',
        qty: qty,
        price: price,
        discount: discountArr,
        net: price > 0 ? String((qty * price * discountArr.reduce((acc, d) => {
          const n = parseFloat(d.replace('%',''));
          return isNaN(n) ? acc : acc * (1 - n/100);
        }, 1)).toFixed(2)) : ''
      });
    }
  }
}

function parseDiscount(s) {
  if (!s) return [];
  const parts = s.split(/[\+\s]+/);
  return parts.map(p => {
    p = p.trim();
    if (p.includes('%')) return p;
    const n = parseFloat(p);
    return !isNaN(n) && n > 0 ? n + '%' : null;
  }).filter(Boolean);
}

const discountArr = parseDiscount(listino_sconto);
if (discountArr.length > 0) {
  items.forEach(item => {
    if (!item.discount || item.discount.length === 0) {
      item.discount = discountArr;
    }
  });
}

return [{
  json: {
    text: allText,
    emailSubject,
    emailBody,
    orders: [{
      customer_name: customer_name || '',
      supplier_name: 'VILLA GUELFA S.R.L.',
      order_number: order_number || '',
      issue_date: issue_date || '',
      delivery_date: delivery_date || '',
      destination: destination || '',
      note_ordine: notes.join(' | ') || '',
      phone: phone || '',
      email: email_addr || '',
      fax: '',
      piva_cliente: piva || '',
      cond_pagamento: cond_pagamento || '',
      listino_sconto: listino_sconto || '',
      items: items
    }]
  }
}];

const results = [];

for (const item of $input.all()) {
  // Handle HTTP Request response structure
  const raw = 
    item.json?.candidates?.[0]?.content?.parts?.[0]?.text ??
    item.json?.text ??
    item.json?.output ??
    '';

  const clean = raw
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  if (!clean || clean === '{}') continue;

  if (!clean.endsWith('}')) {
    results.push({ json: {
      error: true,
      reason: 'truncated',
      message: 'Gemini troncato'
    }});
    continue;
  }

  try {
