const ordersOutput = [];

// 1. SPLIT THE GIANT LIST INTO SEPARATE FILES
// We watch for the title banner to know when a new Excel file begins
const fileChunks = [];
let currentChunk = [];

for (const row of allRows) {
    // If Row 0 (Column A) contains our title banner, start a new chunk!
    if (row && row[0] && typeof row[0] === 'string' && row[0].includes("ORDINE FORNITORE")) {
        if (currentChunk.length > 0) {
            fileChunks.push(currentChunk);
        }
        currentChunk = [];
    }
    currentChunk.push(row);
}
if (currentChunk.length > 0) {
    fileChunks.push(currentChunk);
}

// Helper function to fix Excel dates
function fixDate(excelDate) {
    if (!excelDate) return "-";
    if (!isNaN(excelDate) && typeof excelDate === 'number') {
        const date = new Date(Math.round((excelDate - 25569) * 86400 * 1000));
        const d = String(date.getDate()).padStart(2, '0');
        const m = String(date.getMonth() + 1).padStart(2, '0');
        const y = date.getFullYear();
        return `${d}/${m}/${y}`;
    }
    return excelDate; 
}

// 2. PROCESS EACH EXCEL FILE INDIVIDUALLY
for (const rows of fileChunks) {

    function getCell(rowIndex, colIndex) {
        if (!rows[rowIndex] || rows[rowIndex][colIndex] === null) return "";
        return rows[rowIndex][colIndex];
    }

    const customer_name = getCell(3, 7);
    const piva_cliente = getCell(4, 7);
    const destination = getCell(6, 1);
    const order_number = getCell(3, 1);
    const issue_date = fixDate(getCell(4, 1));
    const delivery_date = fixDate(getCell(5, 1));
    const note_ordine = getCell(7, 1);
    const phone = getCell(7, 7);
    const email = getCell(8, 7);
    const cond_pagamento = getCell(11, 1);
    const listino_sconto = getCell(11, 7);

    const items = [];

    for (let i = 18; i < rows.length; i++) {
        const row = rows[i];
        if (!row || row.length === 0) continue;

        const qty = parseFloat(row[5]);

        if (!isNaN(qty) && qty > 0) {
            let rawDiscount = row[7];
            let discountArr = [];
            if (rawDiscount !== null && rawDiscount !== "") {
                let strDisc = String(rawDiscount);
                if (strDisc.includes('%')) {
                    discountArr = [strDisc];
                } else {
                    let numDisc = parseFloat(strDisc);
                    if (numDisc < 1 && numDisc > 0) {
                        discountArr = [(numDisc * 100).toFixed(0) + "%"];
                    } else {
                        discountArr = [numDisc.toFixed(0) + "%"];
                    }
                }
            }

            items.push({
                "supplier_code": row[1] !== null ? row[1] : "",
                "item_code": row[2] !== null ? row[2] : "",
                "desc": row[3] !== null ? row[3] : "",
                "um": row[4] !== null ? row[4] : "PZ",
                "qty": qty,
                "price": row[6] !== null ? parseFloat(row[6]) : 0,
                "discount": discountArr,
                "net": row[8] !== null ? parseFloat(row[8]) : 0 
            });
        }
    }

    // Package this specific order and add it to our output list
    ordersOutput.push({
        json: {
            orders: [{
                "customer_name": customer_name,
                "supplier_name": "DRINK INTERNATIONAL SPA",
